<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<title>Kanban Board</title>
<style>
  body{font-family:Arial,sans-serif;background:#f0f2f5;margin:0;padding:20px;}
  #board{display:flex;gap:15px;}
  .column{background:white;border-radius:6px;flex:1;display:flex;flex-direction:column;height:80vh;}
  .header{padding:10px;font-weight:bold;background:#e9ecef;border-bottom:1px solid #ddd;display:flex;justify-content:space-between;}
  .card-container{flex:1;padding:10px;overflow-y:auto;}
  .card{background:#fff;border-radius:4px;padding:8px;margin-bottom:6px;box-shadow:0 1px 3px rgba(0,0,0,.1);display:flex;justify-content:space-between;align-items:center;}
  .card-del{background:none;border:none;color:#888;font-size:14px;cursor:pointer;}
  #new-card{width:100%;padding:8px;margin-bottom:10px;border:1px solid #ccc;border-radius:4px;}
  #add-card{padding:8px 12px;background:#007bff;color:white;border:none;border-radius:4px;cursor:pointer;}
</style>
</head>
<body>

<h2>Kanban Board</h2>
<input type="text" id="new-card" placeholder="New task...">
<button id="add-card">Add Card</button>

<div id="board">
  <div class="column" id="col-todo">
    <div class="header">To Do <span class="count"></span></div>
    <div class="card-container" data-col="todo"></div>
  </div>
  <div class="column" id="col-doing">
    <div class="header">Doing <span class="count"></span></div>
    <div class="card-container" data-col="doing"></div>
  </div>
  <div class="column" id="col-done">
    <div class="header">Done <span class="count"></span></div>
    <div class="card-container" data-col="done"></div>
  </div>
</div>

<script>
(() => {
  const STORAGE_KEY = 'kanbanState';
  let state = []; // [{id, title, col}]

  function save() { localStorage.setItem(STORAGE_KEY, JSON.stringify(state)); }

  function load() {
    const data = localStorage.getItem(STORAGE_KEY);
    if (data) state = JSON.parse(data);
  }

  function createCardElement(card) {
    const el = document.createElement('div');
    el.className = 'card';
    el.draggable = true;
    el.dataset.id = card.id;

    const span = document.createElement('span');
    span.textContent = card.title;
    el.appendChild(span);

    const delBtn = document.createElement('button');
    delBtn.className = 'card-del';
    delBtn.innerHTML = '&times;';
    delBtn.onclick = () => deleteCard(card.id);
    el.appendChild(delBtn);

    el.ondragstart = e => {
      e.dataTransfer.setData('text/plain', card.id);
    };
    return el;
  }

  function render() {
    ['todo','doing','done'].forEach(col => {
      const container = document.querySelector(`.card-container[data-col="${col}"]`);
      container.innerHTML = '';
      state.filter(c=>c.col===col).forEach(card=>{
        container.appendChild(createCardElement(card));
      });
      const countEl = container.parentNode.querySelector('.count');
      countEl.textContent = `(${state.filter(c=>c.col===col).length})`;
    });
  }

  function addCard(title) {
    if (!title.trim()) return;
    const id = Date.now() + Math.random().toString(36);
    state.push({id, title: title.trim(), col:'todo'});
    save();
    render();
  }

  function deleteCard(id) {
    state = state.filter(c=>c.id!==id);
    save();
    render();
  }

  // Drag & drop handlers
  document.querySelectorAll('.card-container').forEach(container=>{
    container.ondragover = e => { e.preventDefault(); };
    container.ondrop = e => {
      e.preventDefault();
      const id = e.dataTransfer.getData('text/plain');
      const card = state.find(c=>c.id===id);
      if (!card) return;
      const targetCol = container.dataset.col;
      if (card.col !== targetCol) {
        card.col = targetCol;
        save();
        render();
      }
    };
  });

  // Add button
  document.getElementById('add-card').onclick = () => {
    const input = document.getElementById('new-card');
    addCard(input.value);
    input.value = '';
  };

  load();
  render();
})();
</script>
</body>
</html>
